import { Groq } from 'groq-sdk';
import { NextResponse } from 'next/server';
import dotenv from 'dotenv';
import path from 'path';

export async function POST(req: Request) {
    try {
        // Load config from root directory env file
        dotenv.config({ path: path.resolve(process.cwd(), '../.env') });

        const body = await req.json();
        const { messages } = body;
        const apiKey = process.env.GROQ_API_KEY;

        // Check if the developer updated the key
        if (!apiKey || apiKey === 'SUTITUYE POR EL TUYO') {
            return NextResponse.json(
                { reply: "⚠️ *Error*: No he encontrado la llave de Groq API configurada. Por favor, abre el archivo `.env` en la ruta `C:\\Users\\Usuario\\.gemini\\antigravity\\scratch\\opengravity\\.env` y reemplaza el tag 'SUTITUYE POR EL TUYO' con tu verdadera clave de Groq para que pueda empezar a hablar." },
                { status: 200 } // Send 200 so the UI displays the help text
            );
        }

        const groq = new Groq({ apiKey });

        // Use Llama 3.3 70B as requested
        const response = await groq.chat.completions.create({
            model: 'llama-3.3-70b-versatile',
            messages: messages.map((m: any) => ({
                role: m.role,
                content: m.content
            })),
            max_tokens: 1024,
        });

        const reply = response.choices[0]?.message?.content || "No obtuve respuesta del cerebro...";
        return NextResponse.json({ reply });
    } catch (error: any) {
        console.error("Chat API error:", error);
        return NextResponse.json(
            { reply: `❌ *Error interno*: ${error.message || 'Fallo de API'}. Revisa los logs de servidor.` },
            { status: 500 }
        );
    }
}
